import type {
  FilterFieldPrimitive,
  FilterFieldValuePredicate,
  FilterFieldValuePredicateFn,
  FilterFieldValuePredicateItem,
  FilterFieldValueSuggestionGroupConfig,
} from '../../types/validation.js';
import {
  isFilterFieldRichValuePredicate,
  isFilterFieldValidatorMapDurationSpecification,
  isFilterFieldValidatorMapTypeSpecification,
  isFilterFieldValueSuggestionGroupConfig,
} from '../validation-utils/type-guards.js';
import {
  isValidIPAddress,
  isValidSmartscapeId,
  isValidTimestamp,
  isValidUID,
} from '../validation-utils/type-validators.js';

/**
 * Get a deduplicated list of valid value types and whether literal values are also allowed.
 * @internal
 */
export function getValidValueTypes(
  valuePredicate:
    | FilterFieldValuePredicate
    | FilterFieldValuePredicateFn
    | undefined,
): {
  types: (FilterFieldPrimitive | string)[];
  suggestionType:
    | FilterFieldPrimitive
    | (string & {})
    | (FilterFieldPrimitive | (string & {}))[];
  hasLiteralValues: boolean;
} {
  let valueTypes: (FilterFieldPrimitive | (string & {}))[];
  let hasLiteralValues = false;

  if (typeof valuePredicate === 'function') {
    valueTypes = ['Any'];
  } else {
    ({ types: valueTypes, hasLiteralValues } =
      getTypesFromValuePredicate(valuePredicate));
  }

  valueTypes = Array.from(new Set(valueTypes));
  const suggestionType = getSuggestionTypesFromPrimitiveArray(valueTypes);

  return { types: valueTypes, suggestionType, hasLiteralValues };
}

function getSuggestionTypeForStringSuggestions(valuePredicate: string): {
  types: string[];
  hasLiteralValues: boolean;
} {
  switch (true) {
    case isValidIPAddress(valuePredicate):
      return { types: ['IPAddress'], hasLiteralValues: true };
    case isValidTimestamp(valuePredicate):
      return { types: ['Timestamp'], hasLiteralValues: true };
    case isValidUID(valuePredicate):
      return { types: ['UID'], hasLiteralValues: true };
    case isValidSmartscapeId(valuePredicate):
      return { types: ['SmartscapeId'], hasLiteralValues: true };

    default:
      return { types: ['String'], hasLiteralValues: true };
  }
}

function getTypesFromValuePredicate(
  valuePredicate?: FilterFieldValuePredicate,
): {
  types: (FilterFieldPrimitive | (string & {}))[];
  hasLiteralValues: boolean;
} {
  if (valuePredicate === undefined) {
    return { types: ['Any'], hasLiteralValues: false };
  }

  if (isFilterFieldRichValuePredicate(valuePredicate)) {
    return getTypesFromValuePredicate(valuePredicate.value);
  }

  if (typeof valuePredicate === 'string') {
    return getSuggestionTypeForStringSuggestions(valuePredicate);
  }

  if (typeof valuePredicate === 'number') {
    return { types: ['Number'], hasLiteralValues: true };
  }

  if (typeof valuePredicate === 'boolean') {
    return { types: ['Boolean'], hasLiteralValues: true };
  }

  if (isFilterFieldValidatorMapDurationSpecification(valuePredicate)) {
    return { types: ['Duration'], hasLiteralValues: true };
  }

  if (isFilterFieldValidatorMapTypeSpecification(valuePredicate)) {
    const predicate = valuePredicate.type;

    if (Array.isArray(predicate)) {
      return {
        types: predicate.length > 0 ? Array.from(new Set(predicate)) : ['Any'],
        hasLiteralValues: false,
      };
    }

    return { types: [predicate], hasLiteralValues: false };
  }

  if (isFilterFieldValueSuggestionGroupConfig(valuePredicate)) {
    return { types: ['Any'], hasLiteralValues: true };
  }

  // DEPRECATION: [APPDEV-16872] BREAKING-CHANGE: Clean up after switching to `valueType` prop.
  return getTypesFromPredicateArray(valuePredicate);
}

/**
 * Collect types from all type definitions that may be included in a value predicate array
 * and remove all duplicates.
 */
function getTypesFromPredicateArray(
  valuePredicate: Array<
    FilterFieldValuePredicateItem | FilterFieldValueSuggestionGroupConfig
  >,
): {
  types: (FilterFieldPrimitive | (string & {}))[];
  hasLiteralValues: boolean;
} {
  const types: (FilterFieldPrimitive | (string & {}))[] = [];
  let hasLiteralValues = false;

  for (const predicate of valuePredicate) {
    if (isFilterFieldValidatorMapTypeSpecification(predicate)) {
      if (Array.isArray(predicate.type)) {
        types.push(...predicate.type);
      } else {
        types.push(predicate.type);
      }
    } else {
      hasLiteralValues = true;
    }
  }

  return {
    types: types.length > 0 ? Array.from(new Set(types)) : ['Any'],
    hasLiteralValues,
  };
}

/**
 * Get suggestion types to show for key suggestions.
 * Combines multiple suggestion into 'Any' and only keeps 'JSONPath' as separate type
 * in order to show the normal key suggestion and JSONPath suggestion.
 */
function getSuggestionTypesFromPrimitiveArray(
  primitives: (FilterFieldPrimitive | (string & {}))[],
):
  | FilterFieldPrimitive
  | (string & {})
  | (FilterFieldPrimitive | (string & {}))[] {
  if (primitives.length === 1) {
    return primitives[0];
  }

  if (primitives.includes('JSONPath')) {
    if (primitives.length <= 2) {
      // Make sure that the JSONPath suggestion is always shown last when combined with another type.
      return primitives.sort((a, b) => (a === 'JSONPath' ? 1 : -1));
    }

    return ['Any', 'JSONPath'];
  }

  return 'Any';
}
